qry:select.qry:xquery:
					for $r in sql('
				SELECT 
					POS03_OFERTAS_LAB.d_oferta_lab,
					POS03_OFERTAS_LAB.f_oferta_lab,
					POS03_OFERTAS_LAB.f_cierre,
					POS03_OFERTAS_LAB.oi_oferta_lab,
					POS03_OFERTAS_LAB.c_sexo,
					POS03_OFERTAS_LAB.c_oferta_lab,
					POS03_OFERTAS_LAB.o_oferta_lab,
					ORG35_PROVINCIAS.d_provincia,
					ORG19_LOCALIDADES.d_localidad,
					ORG35_PAISES.d_pais,
					ORG19_ZONAS.d_zona,
					POS04_SENIORITY.d_seniority,
					POS05_AREAS_LAB.d_area_lab
				FROM 
					POS03_OFERTAS_LAB, 
					ORG35_PAISES, 
					ORG35_PROVINCIAS, 
					ORG19_LOCALIDADES, 
					ORG19_ZONAS, 
					POS04_SENIORITY, 
					POS05_AREAS_LAB
				JOIN
					POS03_OFERTAS_LAB.oi_pais LEFT OUTER ORG35_PAISES.oi_pais,
					POS03_OFERTAS_LAB.oi_provincia LEFT OUTER ORG35_PROVINCIAS.oi_provincia,
					POS03_OFERTAS_LAB.oi_localidad LEFT OUTER ORG19_LOCALIDADES.oi_localidad,
					POS03_OFERTAS_LAB.oi_zona LEFT OUTER ORG19_ZONAS.oi_zona,
					POS03_OFERTAS_LAB.oi_seniority LEFT OUTER POS04_SENIORITY.oi_seniority,
					POS03_OFERTAS_LAB.oi_area_lab LEFT OUTER POS05_AREAS_LAB.oi_area_lab
				WHERE 
					1=1                 				
					{%? (#SOURCE:@oi_oferta_lab != '')	
						{% AND POS03_OFERTAS_LAB.oi_oferta_lab = {#SOURCE:@oi_oferta_lab} %} 
						{% %} 
					%}  									
					{%? (#SOURCE:@oi_pais != '')	
						{% AND POS03_OFERTAS_LAB.oi_pais={%=#SOURCE:@oi_pais %} %} 
						{% %} 
					%}
					{%? (#SOURCE:@oi_provincia != '')	
						{% AND POS03_OFERTAS_LAB.oi_provincia={%=#SOURCE:@oi_provincia %} %} 
						{% %} 
					%}    		
					{%? (#SOURCE:@oi_localidad != '')	
						{% AND POS03_OFERTAS_LAB.oi_localidad={%=#SOURCE:@oi_localidad %} %} 
						{% %} 
					%}
					{%? (#SOURCE:@oi_zona != '')	
						{% AND POS03_OFERTAS_LAB.oi_zona={%=#SOURCE:@oi_zona %} %} 
						{% %} 
					%}
					{%? (#SOURCE:@oi_seniority != '')	
						{% AND POS03_OFERTAS_LAB.oi_seniority={%=#SOURCE:@oi_seniority %} %} 
						{% %} 
					%}  
					{%? (#SOURCE:@oi_area_lab != '')	
						{% AND POS03_OFERTAS_LAB.oi_area_lab={%=#SOURCE:@oi_area_lab %} %} 
						{% %} 
					%}    
					{%? (#SOURCE:@f_desde != '')	
						{% AND POS03_OFERTAS_LAB.f_oferta_lab >= {#SOURCE:@f_desde} %} 
						{% %} 
					%}     
					{%? (#SOURCE:@f_hasta != '')	
						{% AND POS03_OFERTAS_LAB.f_oferta_lab <= {#SOURCE:@f_hasta} %} 
						{% %} 
					%}     
					{%? (#SOURCE:@c_sexo != '')	
						{% AND POS03_OFERTAS_LAB.c_sexo = {#SOURCE:@c_sexo} %} 
						{% %}
					%}
        	AND (ISNULL(POS03_OFERTAS_LAB.f_cierre) 
        	OR POS03_OFERTAS_LAB.f_cierre >= now())
        ORDER BY f_oferta_lab DESC
			')/ROWS/ROW

for $r in #SOURCE:ROW[contains(upper_case(@c_oferta_lab),upper_case(#SOURCE:../@palabraclave)) 
or contains(upper_case(@d_oferta_lab),upper_case(#SOURCE:../@palabraclave)) 
or contains(upper_case(@o_oferta_lab),upper_case(#SOURCE:../@palabraclave))]

		for $r in sql('
SELECT 
	POS16_CONOCIMIENTOS.oi_conocimiento as id,
	POS16_CONOCIMIENTOS.d_conocimiento AS descr
FROM 
	POS16_CONOCIMIENTOS
WHERE 1 = 1
	{%? (string(#SOURCE:@grupo)='') {% AND 2 = 1 %} {% %} %}
	{%? (string(#SOURCE:@grupo)='A') {% AND POS16_CONOCIMIENTOS.l_administrativo = 1 %} {% %} %}
	{%? (string(#SOURCE:@grupo)='I') {% AND POS16_CONOCIMIENTOS.l_industrial     = 1 %} {% %} %}
	{%? (string(#SOURCE:@grupo)='F') {% AND POS16_CONOCIMIENTOS.l_informatico    = 1 %} {% %} %}
	{%? (string(#SOURCE:@grupo)='P') {% AND POS16_CONOCIMIENTOS.l_promotora      = 1 %} {% %} %}
	{%? (string(#SOURCE:@grupo)='T') {% AND POS16_CONOCIMIENTOS.l_tecnico        = 1 %} {% %} %}
	{%? (string(#SOURCE:@grupo)='M') {% AND POS16_CONOCIMIENTOS.l_merchandiser   = 1 %} {% %} %}						
	{%? (string(#SOURCE:CONOC_CV/CONOC_CV[@nmd-status!='~d,' and @nmd-status!='~x,']/oi_conocimiento/@value)!='') {% AND POS16_CONOCIMIENTOS.oi_conocimiento NOT IN ({%=string(#SOURCE:CONOC_CV/CONOC_CV[@nmd-status!='~d,' and @nmd-status!='~x,']/oi_conocimiento/@value) %}) %} {% %} %}
ORDER BY 
	descr ASC	
')/ROWS/ROW
